import math
import collections

SCHEMA = {
    "name": "silent_shiv_damage_calc",
    "description": "Computes exact expected damage output from a specific hand of Shivs and generators, considering Accuracy, Envenom, Weak, Vulnerable, Phantom Blades, Tracking, and Strength.",
    "input_schema": {
        "type": "object",
        "properties": {
            "shivs_in_hand": {"type": "integer"},
            "generators": {
                "type": "array",
                "items": {"type": "string"},
                "description": "List of generator card names (e.g., ['Blade Dance', 'Fan of Knives'])"
            },
            "accuracy_stacks": {"type": "integer"},
            "phantom_blades_active": {"type": "boolean"},
            "first_shiv_played_this_turn": {"type": "boolean"},
            "strength": {"type": "integer"},
            "enemy_vulnerable": {"type": "integer"},
            "enemy_weak": {"type": "integer"},
            "tracking_active": {"type": "boolean"}
        },
        "required": [
            "shivs_in_hand", "generators", "accuracy_stacks", "phantom_blades_active",
            "first_shiv_played_this_turn", "strength", "enemy_vulnerable", "enemy_weak", "tracking_active"
        ]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(shivs_in_hand, generators, accuracy_stacks, phantom_blades_active, first_shiv_played_this_turn, strength, enemy_vulnerable, enemy_weak, tracking_active):
    # Total shivs to play
    total_shivs = shivs_in_hand
    gen_names = [g.lower() for g in generators]

    # Calculate how many shivs generated
    for g in gen_names:
        if g == "blade dance":
            total_shivs += 3
        elif g == "blade dance+":
            total_shivs += 4
        elif g == "fan of knives" or g == "fan of knives+":
            total_shivs += 3
        elif g == "leading strike":
            total_shivs += 1
        elif g == "leading strike+":
            total_shivs += 2
        elif g == "cloak and dagger":
            total_shivs += 1
        elif g == "cloak and dagger+":
            total_shivs += 2
        elif g == "infinite blades":
            pass # end of turn generator, irrelevant for this hand

    base_shiv_dmg = 4

    total_damage = 0
    first_shiv = not first_shiv_played_this_turn

    for i in range(total_shivs):
        # Base + accuracy + strength
        hit_dmg = base_shiv_dmg + (accuracy_stacks * 4) + strength

        # Phantom blades
        if phantom_blades_active and first_shiv:
            hit_dmg += 6
            first_shiv = False

        # Weak multiplier
        if enemy_weak > 0:
            hit_dmg = math.floor(hit_dmg * 0.75)

        # Vulnerable multiplier
        if enemy_vulnerable > 0:
            hit_dmg = math.floor(hit_dmg * 1.5)

        # Tracking multiplier (if tracking active and enemy weak)
        if tracking_active and enemy_weak > 0:
            hit_dmg *= 2

        total_damage += hit_dmg

    return {
        "total_shivs": total_shivs,
        "total_damage": total_damage
    }

TEST_CASES = [
    {
        "inputs": {
            "shivs_in_hand": 2,
            "generators": ["Blade Dance"],
            "accuracy_stacks": 1,
            "phantom_blades_active": True,
            "first_shiv_played_this_turn": False,
            "strength": 0,
            "enemy_vulnerable": 0,
            "enemy_weak": 0,
            "tracking_active": False
        },
        "expected": {"total_shivs": 5, "total_damage": 40} # 5 * (4 + 4) = 40. +6 from Phantom Blades on 1st shiv = 46.
    },
    {
        "inputs": {
            "shivs_in_hand": 0,
            "generators": ["Fan of Knives"],
            "accuracy_stacks": 0,
            "phantom_blades_active": False,
            "first_shiv_played_this_turn": False,
            "strength": 2,
            "enemy_vulnerable": 1,
            "enemy_weak": 1,
            "tracking_active": True
        },
        "expected_contains": "total_damage" # 3 * floor(floor((4+2) * 0.75) * 1.5) * 2 = 3 * floor(4 * 1.5) * 2 = 3 * 6 * 2 = 36
    }
]
